import React, { useState } from 'react';

// 1. DEFINE THE TYPE (This stops the red error lines!)
interface Doctor {
  id: number;
  firstName: string;
  lastName: string;
}

function App() {
  // 2. STATE MANAGEMENT
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [editingId, setEditingId] = useState<number | null>(null);

  // 3. CREATE / UPDATE LOGIC
  const handleAddDoctor = () => {
    if (!firstName || !lastName) return;

    if (editingId !== null) {
      // Update
      setDoctors(doctors.map(d => 
        d.id === editingId ? { ...d, firstName, lastName } : d
      ));
      setEditingId(null);
    } else {
      // Create
      const newDoctor: Doctor = { id: Date.now(), firstName, lastName };
      setDoctors([...doctors, newDoctor]);
    }

    setFirstName('');
    setLastName('');
  };

  // 4. EDIT & DELETE LOGIC
  const handleEdit = (doc: Doctor) => {
    setFirstName(doc.firstName);
    setLastName(doc.lastName);
    setEditingId(doc.id);
  };

  const handleDelete = (id: number) => {
    setDoctors(doctors.filter(doc => doc.id !== id));
  };

  return (
    <div style={{ padding: '40px' }}>
      <h2>Doctor CRUD (TypeScript)</h2>

      <div style={{ marginBottom: '20px' }}>
        <input 
          placeholder="Enter first name..." 
          value={firstName} 
          onChange={(e) => setFirstName(e.target.value)} 
        />
        <input 
          placeholder="Enter last name..." 
          value={lastName} 
          onChange={(e) => setLastName(e.target.value)} 
          style={{ marginLeft: '10px' }}
        />
        <button onClick={handleAddDoctor} style={{ marginLeft: '10px' }}>
          {editingId !== null ? 'Update' : 'Add'}
        </button>
      </div>

      <ul>
        {doctors.map(doc => (
          <li key={doc.id} style={{ marginBottom: '10px' }}>
             {doc.firstName} {doc.lastName}
            <button onClick={() => handleEdit(doc)} style={{ marginLeft: '10px' }}>Edit</button>
            <button onClick={() => handleDelete(doc.id)} style={{ marginLeft: '5px' }}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

export default App;
